import{_ as s,o as n,c as t,a1 as p}from"./chunks/framework.BKJzsOC1.js";const u=JSON.parse('{"title":"第七章：相对强弱与高位末端冲刺","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/07-relative-strength-and-late-sprint.md","filePath":"trading/intraday-entry/07-relative-strength-and-late-sprint.md"}'),e={name:"trading/intraday-entry/07-relative-strength-and-late-sprint.md"};function i(l,a,d,c,o,h){return n(),t("div",null,[...a[0]||(a[0]=[p(`<h1 id="第七章-相对强弱与高位末端冲刺" tabindex="-1">第七章：相对强弱与高位末端冲刺 <a class="header-anchor" href="#第七章-相对强弱与高位末端冲刺" aria-label="Permalink to &quot;第七章：相对强弱与高位末端冲刺&quot;">​</a></h1><blockquote><p>强势股不一定适合立即买入；真正有价值的是“强势仍然处于可控风险的位置”。</p></blockquote><h2 id="一、相对强弱到底是什么" tabindex="-1">一、相对强弱到底是什么 <a class="header-anchor" href="#一、相对强弱到底是什么" aria-label="Permalink to &quot;一、相对强弱到底是什么&quot;">​</a></h2><p>相对强弱不是简单比较谁涨得多，而是观察个股相对于 SPX、NQ 或所属板块的行为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大盘回调时，个股抗跌；</span></span>
<span class="line"><span>大盘重新转强时，个股领涨；</span></span>
<span class="line"><span>回踩时仍然守住需求区、VWAP或前一个更高低点。</span></span></code></pre></div><p>因此，真正的相对强势至少包含两段证据：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>抗跌 → 领涨</span></span></code></pre></div><p>只有单独一段快速上涨，不能直接定义为高质量相对强势。</p><h2 id="二、四种常见状态" tabindex="-1">二、四种常见状态 <a class="header-anchor" href="#二、四种常见状态" aria-label="Permalink to &quot;二、四种常见状态&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;先看 SPX / NQ 环境&quot;] --&gt; B{&quot;大盘是否支持做多？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|是| C{&quot;个股是否在需求区或VWAP附近？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|否| D{&quot;个股是否在供应区或VWAP下方？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|是| E[&quot;优先观察多头：等待③&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|否，已进入Premium高位| F[&quot;强，但不追多&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|是| G[&quot;优先观察空头：等待③&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|否，已进入Discount低位| H[&quot;不追空，等待反弹或重新破位&quot;]</span></span></code></pre></div><h3 id="_1-大盘支持-个股在需求区" tabindex="-1">1. 大盘支持，个股在需求区 <a class="header-anchor" href="#_1-大盘支持-个股在需求区" aria-label="Permalink to &quot;1. 大盘支持，个股在需求区&quot;">​</a></h3><p>这是最理想的多头筛选环境：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPX/NQ在VWAP上方</span></span>
<span class="line"><span>→ 个股回踩需求区</span></span>
<span class="line"><span>→ 个股不破结构低点</span></span>
<span class="line"><span>→ 收回VWAP或关键线</span></span>
<span class="line"><span>→ ③再次启动</span></span></code></pre></div><p>这里的③仍然是：回踩守住后，价格重新突破回踩结构的小高点。它不是第三根K线，也不是指标箭头。</p><h3 id="_2-大盘支持-个股已经在高位供应区" tabindex="-1">2. 大盘支持，个股已经在高位供应区 <a class="header-anchor" href="#_2-大盘支持-个股已经在高位供应区" aria-label="Permalink to &quot;2. 大盘支持，个股已经在高位供应区&quot;">​</a></h3><p>例如个股快速拉升到 Premium、Supply、Strong High 或 Weak High 附近。此时标的可能仍然很强，但入场位置已经变差：</p><ul><li>离 VWAP 太远；</li><li>结构止损距离变大；</li><li>距离上方目标变近；</li><li>容易出现冲高回落。</li></ul><p>正确处理是等待：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破前高并回踩守住</span></span></code></pre></div><p>或者：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>回落到VWAP/需求区</span></span>
<span class="line"><span>→ 守住</span></span>
<span class="line"><span>→ ③再次启动</span></span></code></pre></div><p>强势不等于现在可以买。</p><h3 id="_3-大盘偏弱-个股在高位供应区" tabindex="-1">3. 大盘偏弱，个股在高位供应区 <a class="header-anchor" href="#_3-大盘偏弱-个股在高位供应区" aria-label="Permalink to &quot;3. 大盘偏弱，个股在高位供应区&quot;">​</a></h3><p>这是空头观察条件较好的组合：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPX/NQ跌破VWAP</span></span>
<span class="line"><span>→ 个股在Premium或Supply受阻</span></span>
<span class="line"><span>→ 形成更低高点</span></span>
<span class="line"><span>→ 跌破回踩低点</span></span>
<span class="line"><span>→ ③向下启动</span></span></code></pre></div><p>不能因为价格进入红色区域就立即做空，必须等拒绝和结构确认。</p><h3 id="_4-大盘偏弱-个股已经在低位需求区" tabindex="-1">4. 大盘偏弱，个股已经在低位需求区 <a class="header-anchor" href="#_4-大盘偏弱-个股已经在低位需求区" aria-label="Permalink to &quot;4. 大盘偏弱，个股已经在低位需求区&quot;">​</a></h3><p>个股虽然偏弱，但如果已经接近 Demand 或 Discount，继续追空容易卖在支撑上。</p><p>更科学的空头条件是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需求区被跌破</span></span>
<span class="line"><span>→ 实体收线确认</span></span>
<span class="line"><span>→ 反抽不过</span></span>
<span class="line"><span>→ ③向下启动</span></span></code></pre></div><p>没有破位和反抽失败时，只观察，不追空。</p><h2 id="三、真正强势与高位末端冲刺" tabindex="-1">三、真正强势与高位末端冲刺 <a class="header-anchor" href="#三、真正强势与高位末端冲刺" aria-label="Permalink to &quot;三、真正强势与高位末端冲刺&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>价格位置</th><th>回踩质量</th><th>大盘同步</th><th>处理</th></tr></thead><tbody><tr><td>真正相对强势</td><td>需求区、VWAP或新结构附近</td><td>缩量且守住</td><td>同步转强</td><td>等③做多</td></tr><tr><td>高位末端冲刺</td><td>Premium、Supply或前高附近</td><td>没有低风险回踩</td><td>同步减弱或停滞</td><td>不追，等新结构</td></tr><tr><td>弱势反弹</td><td>低位需求区上方</td><td>反弹无法收复压力</td><td>大盘偏弱</td><td>不追空，等破位</td></tr><tr><td>中间噪音</td><td>两个区域之间</td><td>反复穿越VWAP</td><td>市场分化</td><td>观望</td></tr></tbody></table><h3 id="高位末端冲刺的常见特征" tabindex="-1">高位末端冲刺的常见特征 <a class="header-anchor" href="#高位末端冲刺的常见特征" aria-label="Permalink to &quot;高位末端冲刺的常见特征&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>快速拉升</span></span>
<span class="line"><span>→ 远离VWAP</span></span>
<span class="line"><span>→ 进入Premium/供应区</span></span>
<span class="line"><span>→ 成交量放大但实体变小</span></span>
<span class="line"><span>→ 上影线增加</span></span>
<span class="line"><span>→ 大盘不再同步</span></span>
<span class="line"><span>→ 高位横盘或回落</span></span></code></pre></div><p>这类行情最容易让人产生“它这么强，不能空，所以只能买”的错觉。实际上，不能做空和不能追多可以同时成立。</p><h2 id="四、用六宫格筛选个股" tabindex="-1">四、用六宫格筛选个股 <a class="header-anchor" href="#四、用六宫格筛选个股" aria-label="Permalink to &quot;四、用六宫格筛选个股&quot;">​</a></h2><p>复盘六只大型科技股时，可以依次问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. SPX/NQ当前支持多头还是空头？</span></span>
<span class="line"><span>2. 这只股票相对大盘是抗跌、同步还是落后？</span></span>
<span class="line"><span>3. 价格在Demand、Equilibrium还是Premium？</span></span>
<span class="line"><span>4. VWAP在价格下方还是上方？</span></span>
<span class="line"><span>5. 回踩是否缩量并守住结构？</span></span>
<span class="line"><span>6. 是否已经完成③？</span></span></code></pre></div><p>刚才的示例可以这样分类：</p><ul><li>TSLA：相对强，但进入高位供应区，属于“强但不追”；</li><li>NVDA：冲高回落后测试支撑，需求区守住后才观察多头；</li><li>AAPL：需求区反弹，但尚未收复上方压力；</li><li>GOOGL：相对偏弱但接近需求区，不宜继续追空；</li><li>META：下跌后反弹到平衡区，方向和位置都不够清楚；</li><li>MSFT：相对稳定，但处于区间中间，仍需等待边界突破。</li></ul><p>这些是截图复盘中的历史状态，不是后续交易点位。</p><h2 id="五、执行规则" tabindex="-1">五、执行规则 <a class="header-anchor" href="#五、执行规则" aria-label="Permalink to &quot;五、执行规则&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大盘方向：能不能做</span></span>
<span class="line"><span>个股强弱：选谁做</span></span>
<span class="line"><span>需求/供应区：在哪里做</span></span>
<span class="line"><span>VWAP：环境是否支持</span></span>
<span class="line"><span>③：现在能不能执行</span></span></code></pre></div><p>做多的最小证据链：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大盘同侧</span></span>
<span class="line"><span>→ 个股在低风险位置</span></span>
<span class="line"><span>→ 回踩守住</span></span>
<span class="line"><span>→ 突破回踩结构</span></span>
<span class="line"><span>→ ③再次启动</span></span></code></pre></div><p>做空的最小证据链：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大盘同侧</span></span>
<span class="line"><span>→ 个股在高位供应区或VWAP下方</span></span>
<span class="line"><span>→ 反抽失败</span></span>
<span class="line"><span>→ 跌破回踩结构</span></span>
<span class="line"><span>→ ③向下启动</span></span></code></pre></div><p>本章最终原则：</p><blockquote><p>相对强弱负责筛选标的，需求/供应区负责筛选位置，③负责触发建仓。</p></blockquote>`,50)])])}const g=s(e,[["render",i]]);export{u as __pageData,g as default};
